sql:
SELECT DISTINCT c.customer_id, c.name
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;

external_knowledge:
- "voyagers" refers to customers who have placed orders;
- "sailing under the FedEx flag" means their orders are shipped by FedEx;
- "identities and harbor addresses" are metaphorical terms for customer ID and name.

sql:
SELECT COUNT(*)
FROM (
  SELECT DISTINCT order_id FROM returns
  UNION
  SELECT DISTINCT order_id FROM cancellations
) AS combined_orders;
